// src/components/home.jsx
import React, { useEffect, useState, useRef } from "react";
import "../styles/home.css";
import { Link } from "react-router-dom";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function Home({ rooms: initialRooms = [], photos = [] }) {
  const [index, setIndex] = useState(1);
  const slideCount = 3;
  const autoPlayRef = useRef(null);

  // rooms state (will use initialRooms if provided, otherwise fetch)
  const [rooms, setRooms] = useState(Array.isArray(initialRooms) ? initialRooms : []);
  const [loadingRooms, setLoadingRooms] = useState(false);
  const [roomsError, setRoomsError] = useState("");
  const [rawResponse, setRawResponse] = useState(null);

  useEffect(() => {
    autoPlayRef.current = setInterval(() => {
      setIndex((i) => (i >= slideCount ? 1 : i + 1));
    }, 6000);
    return () => clearInterval(autoPlayRef.current);
  }, []);

  useEffect(() => {
    // Intersection observer (unchanged)
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) entry.target.classList.add("show");
        });
      },
      { threshold: 0.1 }
    );

    document.querySelectorAll(".fade-in, .fade-up, .fade-left, .fade-right").forEach((el) => {
      if (!el.closest(".hero-wrap") && !el.closest(".nav")) observer.observe(el);
    });
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    if (Array.isArray(initialRooms) && initialRooms.length > 0) {
      setRooms(initialRooms.map(normalizeRoom));
      return;
    }
    fetchRooms();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  async function fetchRooms() {
    setLoadingRooms(true);
    setRoomsError("");
    setRawResponse(null);
    try {
      const res = await axios.get(`${API_BASE}/api/rooms/`);
      console.log("GET /api/rooms/ response:", res);
      setRawResponse(res.data);
      const data = Array.isArray(res.data) ? res.data : res.data.results || [];
      const normalized = data.map(normalizeRoom).filter(Boolean);
      if (normalized.length === 0) {
        // If normalization produced nothing, keep raw but show message for debugging
        setRooms([]);
        setRoomsError("No rooms normalized from API — see raw JSON below (check console).");
      } else {
        setRooms(normalized);
      }
    } catch (err) {
      console.error("Failed fetching rooms:", err);
      setRoomsError(err?.message || "Unable to load rooms. Check server / CORS.");
      setRawResponse(err?.response?.data ?? null);
    } finally {
      setLoadingRooms(false);
    }
  }

  // Normalize room object returned by backend into fields used by UI
  function normalizeRoom(r) {
  if (!r) return null;

  const id = r.id ?? r.room_id ?? null;
  const room_name = r.room_name ?? r.name ?? "";
  const description = r.description ?? "";
  const capacity = r.capacity ?? r.guests ?? r.max_guests ?? "";
  const price = r.price ?? r.rate ?? 0;

  // Helper
  const extractSrc = (img) => {
    if (!img) return null;
    if (typeof img === "string") return img;
    if (typeof img === "object") {
      return img.url ?? img.image ?? img.image_path ?? img.path ?? img.src ?? null;
    }
    return null;
  };

  const imgs = r.images ?? r.room_images ?? r.images_list ?? [];
  let preview = null;

  if (Array.isArray(imgs) && imgs.length > 0) {
    const first = imgs[0];
    preview =
      extractSrc(first) ||
      (first.image && extractSrc(first.image)) ||
      null;
  }

  // fallback fields
  if (!preview) {
    preview =
      extractSrc(r.preview_image) ||
      extractSrc(r.image) ||
      extractSrc(r.image_path) ||
      extractSrc(r.thumbnail) ||
      null;
  }

  // normalize URL
  let image = "/assets/images/uploads/default.jpg";
  if (preview && typeof preview === "string") {
    if (preview.startsWith("http")) image = preview;
    else if (preview.startsWith("/")) image = `${API_BASE}${preview}`;
    else image = `${API_BASE}/${preview}`;
  }

  return {
    id,
    room_id: id,
    room_name,
    description,
    capacity,
    price,
    image,
    raw: r,
  };
}


  const slideBackground = (n) => {
    const urls = { 1: "/assets/images/glamp1.jpg", 2: "/assets/images/glamp2.jpg", 3: "/assets/images/glamp3.jpg" };
    return { backgroundImage: `url('${urls[n]}')` };
  };
  const goPrev = () => setIndex((i) => (i <= 1 ? slideCount : i - 1));
  const goNext = () => setIndex((i) => (i >= slideCount ? 1 : i + 1));

  return (
    <div id="app">
      {/* ... slider, nav, hero same as before (omitted here for brevity) */}
      <div className="slider" id="slider">
        <div className={`slide slide-1 ${index === 1 ? "active" : ""}`} role="img" aria-label="Slide 1" style={slideBackground(1)} />
        <div className={`slide slide-2 ${index === 2 ? "active" : ""}`} role="img" aria-label="Slide 2" style={slideBackground(2)} />
        <div className={`slide slide_3 ${index === 3 ? "active" : ""}`} role="img" aria-label="Slide 3" style={slideBackground(3)} />

        <header className="nav">
          <div className="nav-inner">
            <div className="brand">
              <img src="/assets/images/glamp_logo.png" alt="Glamp Logo" className="logo" />
            </div>
            <nav className="menu">
              <a href="/">Home</a>
              <a href="#rooms">Rooms</a>
              <Link to="/reservation">Reservation</Link>
              <a href="#">Pages</a>
              <a href="#">News</a>
              <a href="#">Contact</a>
              <a className="reserve" href="/reservation/">
                RESERVATION
              </a>
            </nav>
          </div>
        </header>

        <div className="arrow left" onClick={goPrev}>
          <button aria-label="previous">‹</button>
        </div>
        <div className="arrow right" onClick={goNext}>
          <button aria-label="next">›</button>
        </div>

        <div className="hero-wrap">
          <section className="arch">
            <div className="arch-inner">
              <div className="stars-row">★★★★★</div>
              <h1>
                Experience Hospitality Like
                <br />
                Never Before
              </h1>
              <p className="lead">Discover the perfect blend of luxury, comfort, and convenience at The Paradise Glamp</p>
              <a className="cta" href="#rooms">
                DISCOVER ROOMS
              </a>
            </div>
          </section>
        </div>

        <div className="dots">{[1, 2, 3].map((n) => <button key={n} className={`dot ${index === n ? "active" : ""}`} onClick={() => setIndex(n)} />)}</div>
        <div className="page-indicator">{index} / {slideCount}</div>
      </div>

      {/* ACCOMMODATION */}
      <section className="accommodation fade-up" id="rooms">
        <div className="accommodation-inner">
          <div className="section-title fade-up"><span className="subtitle">ELEGANT</span><h2>Accommodation</h2></div>

          {loadingRooms ? (
            <p>Loading rooms...</p>
          ) : rooms.length > 0 ? (
            rooms.map((room) => (
              <div className="room-card fade-up" key={room.room_id ?? room.id}>
                <div className="arch-img">
                  <img src={room.image || "/assets/images/uploads/default.jpg"} alt={room.room_name} />
                  <div className="room-info">
                    <h3>{room.room_name}</h3>
                    <p>{room.capacity} Guests</p>
                  </div>
                  <div className="overlay">
                    <span className="price">From ₹{Number(room.price).toFixed(2)}</span>
                    <Link to={`/room/${room.room_id ?? room.id}`} className="details-btn">View Details</Link>
                  </div>
                </div>
              </div>
            ))
          ) : (
            <>
              <p>No rooms available at the moment.</p>
              {roomsError && <div style={{ color: "#ff8a8a", marginTop: 12 }}>{roomsError}</div>}
              {rawResponse && (
                <div style={{ marginTop: 12, background: "#111", padding: 12, borderRadius: 6, color: "#ddd", fontSize: 13 }}>
                  <strong>Raw API response (for debugging):</strong>
                  <pre style={{ whiteSpace: "pre-wrap", marginTop: 8 }}>{JSON.stringify(rawResponse, null, 2)}</pre>
                </div>
              )}
            </>
          )}
        </div>
      </section>

      {/* rest of your page (video, instagram, footer) unchanged */}
      {/* ... */}
    </div>
  );
}
